// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const searchWorkers = async (workType) => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter((worker) =>
        worker.skills.includes(workType)
      );

      setWorkers(filtered);
    } catch (err) {
      console.log(err);
    }
  };

  const sendRequest = async () => {
    if (!form.workType || !form.labourId || !form.location || !form.date) {
      return alert("Please fill all fields");
    }

    try {
      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"]
        }
      );

      alert("Request Sent Successfully");

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  const customerDecision = async (id, decision) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/customer-decision/${id}`,
        { decision }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) {
      return alert("Please enter rating and review");
    }

    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      alert("Feedback Submitted");
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT */}
        <div style={styles.card}>

          <h2 style={styles.heading}>Hire Workers</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({ ...form, workType: e.target.value });
              searchWorkers(e.target.value);
            }}
          >
            <option value="">Select Work</option>
            {jobs.map((job, i) => (
              <option key={i} value={job}>{job}</option>
            ))}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {
                const worker = workers.find(
                  (w) => w._id === e.target.value
                );

                setForm({
                  ...form,
                  labourId: worker._id,
                  labourName: worker.name
                });
              }}
            >
              <option>Select Worker</option>
              {workers.map((w) => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Location"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <button style={styles.button} onClick={sendRequest}>
            Send Request
          </button>

        </div>

        {/* RIGHT */}
        <div style={styles.card}>

          <h2 style={styles.heading}>My Requests</h2>

          {requests.length === 0 && (
            <p style={{ color: "#aaa" }}>No Requests Found</p>
          )}

          {requests.map((req) => (
            <div key={req._id} style={styles.requestBox}>

              <h3 style={{ color: "#f97316" }}>
                {req.labourName}
              </h3>

              <p>{req.workType}</p>
              <p>{req.location}</p>
              <p>{req.date}</p>

              <p>Status: {req.status}</p>
              <p>Labour: {req.labourResponse}</p>
              <p>Price: ₹{req.labourPrice}</p>

              {req.labourResponse === "Accepted" &&
                req.customerDecision === "Waiting" && (
                  <div style={styles.row}>
                    <button
                      style={styles.accept}
                      onClick={() => customerDecision(req._id, "Accepted")}
                    >
                      Accept
                    </button>

                    <button
                      style={styles.reject}
                      onClick={() => customerDecision(req._id, "Rejected")}
                    >
                      Reject
                    </button>
                  </div>
                )}

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#0f172a",
    color: "white"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px"
  },

  card: {
    background: "#111827",
    border: "1px solid #f97316",
    borderRadius: "16px",
    padding: "20px"
  },

  heading: {
    color: "#f97316",
    marginBottom: "15px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginBottom: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white"
  },

  button: {
    width: "100%",
    padding: "12px",
    background: "#f97316",
    border: "none",
    borderRadius: "10px",
    color: "white",
    fontWeight: "bold",
    cursor: "pointer"
  },

  requestBox: {
    border: "1px solid #374151",
    padding: "15px",
    borderRadius: "12px",
    marginBottom: "12px",
    background: "#1f2937"
  },

  row: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  accept: {
    flex: 1,
    background: "green",
    border: "none",
    padding: "8px",
    borderRadius: "8px",
    color: "white"
  },

  reject: {
    flex: 1,
    background: "red",
    border: "none",
    padding: "8px",
    borderRadius: "8px",
    color: "white"
  }
};
